class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 Breaking Change #1: Discriminator property renamed to "$type".
            // Existing 500K docs use "Discriminator". Opt back in to the old name:
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 Breaking Change #2: Id format changed from "EntityName|Key" to just the key.
            // Existing docs have ids like "Product|123". Opt back in to the old format:
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGenerator>();

            // EF Core 9 Breaking Change #3: Indexes (HasIndex) are no longer silently ignored —
            // they now throw. Remove the HasIndex call or use ETag concurrency instead.
        });
    }
}
